INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (20, 'multiple', '下圖為低態動作的三態閘，下列敘述何者正確？', '當B=0 時，C=A=1,當B=0 時，C=A=0,當B=1 時，C=A=1,當B=1 時，C=A=0 ', '0,1', 'backend/data/img/11700_img/1-20-x.jpg');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (21, 'multiple', '下圖所示，下列敘述何者正確？', '互補式輸出的緩衝器，當D=0 時，E=0 及F=1,互補式輸出的緩衝器，當D=1 時，E=1 及F=0,互補式輸出的 反相器，當D=0 時，E=1 及F=0,互補式輸出的反相器，當D=1 時，E=0 及F=1 ', '0,1', 'backend/data/img/11700_img/1-21-x.jpg');
