INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (28, 'multiple', '有關印刷電路板元件面的安排與繪製，下列敘述何者正確？', '以IC 或電 晶體位置為中心向外安排其他元件,IC 依形狀擺放不需特別標示腳位,連接器必須標示第一腳位,並排電阻盡量靠近以節省空間及連接線 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (53, 'multiple', '25. (234) 有關含有一個小數點的七段顯示器敘述，下列何者正確？', '9 隻接腳,10 隻接腳,CA 型或CK 型,8 顆LED 所組成 ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (54, 'multiple', '26. (23) 下圖所示，下列敘述何者正確？','', 'Pre 接0 時，輸出Q=0,Pre 接0 時， 輸出Q=1,Clr 接0 時，輸出Q=0,Clr 接0 時，輸出Q=1 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (55, 'multiple', '27. (12) 下列何者是穩壓IC 的型號類別？', 'LM78XX,LD1117-XX,NE555-X,EPM3064-ALCXX ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (56, 'multiple', '28. (123) 有關固態繼電器（Solid State Relay）的敘述，下列何者正確？', '一種電 子式無接點開關,內部含有發光二極體與光電晶體組成光耦合器,利用 低電壓控制高電壓之驅動裝置,利用高電流控制低電流之驅動裝置 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (57, 'multiple', '29. (14) 下圖所示，感溫IC AD590 的溫度係數為1μA/K，25°C 時，其端電流為 298.2μA，則下列敘述何者正確？', '0°C 時，其端電流為273.2μA,0° C 時，Vo=0V,15°C 時，Vo=0.15V,25°C 時，Vo=2.982V ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (58, 'multiple', '30. (13) 若白金感溫電阻Pt100 之電阻溫度係數為3850ppm/°C，下列敘述何者正 確？', '每1°C 電阻變化量為0.385Ω,每1°C 電阻變化量為3.85Ω,0°C 時，其電阻值為100Ω,常溫25°C 時，其電阻值為100Ω ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (59, 'multiple', '31. (123) 應用於感測器模組中，除微控制器外尚會使用下列哪幾項元件？', '現場 可程式化邏輯閘陣列（Field-Programmable Gate Arrays, FPGA）,複雜 的可規劃邏輯元件（Complex Programmable Logic Device, CPLD）,特 殊應用積體電路（Application-Specific Integrated Circuit, ASIC）,中央 處理器（Central Processing Unit, CPU） ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (60, 'multiple', '32. (14) 常用的陶瓷及薄膜電容器代碼標示，下列敘述何者正確？', '102J 是指電 容值為10×102pf±5％,221M 是指電容值為22×10 1pf±15％,104G 是指 電容值為10×10 4pf±1％,100K 是指電容值為100pf±10％ ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (61, 'multiple', '33. (13) 有關電荷電位敘述，下列何者正確？', '愈靠近正電荷處電位愈高,有方 向性,距電場無窮遠處之電位為零,與溫度成正比 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (116, 'multiple', '55. (24) IEEE-488 標準介面的相關規定中，下列敘述何者正確？', '屬於儀器中的 串列通信介面,可連接的儀器裝置最多不能超過15 台,各裝置間的通 信距離不能超過20 公尺,傳輸的信號為標準TTL 位準，且採用負邏輯 方式 ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (117, 'multiple', '56. (13) 一般電路模擬軟體工具為避免量測電壓時而產生負載效應，其電壓表的內 阻合理設定值可為', '10G,1M,1G,100K ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (118, 'multiple', '57. (13) 一般指針式電表內部不裝電池時，可用來量測', '電壓值,電阻值,電流 值,電感值 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (119, 'multiple', '58. (123) 三用電表主要功能是用來量測下列哪幾種物理量？', '電壓（Volt）,電 阻（Ohm）,電流（Ampere）,電容（Farad） ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (120, 'multiple', '59. (124) 下列敘述何者正確？', '電壓表之靈敏度通常以歐姆伏特比（Ω/V）表示,電壓表之內阻值愈大，則靈敏度愈佳,電流表內阻值愈大，則負載效 PAGE 12 of 85 應愈小,瓦特表係同時測量待測物的電壓與電流值而獲得待測物之消耗 功率 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (121, 'multiple', '60. (13) 使用日系指針式三用電表時，下列敘述何者正確？', '量測電壓時，電表 與待測者並聯,量測電流時，電表與待測者並聯,量測電阻時，電表需 先作歸零,設定於歐姆檔時，紅、黑色測試棒分別代表內部電池的正端 與負端 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (122, 'multiple', '61. (12) 下圖之直流電源供應器使用，下列敘述何者正確？', '獨立模式：可分別 調整輸出電壓及限定電流的大小,串聯追蹤模式：兩組電源的輸出電壓 值相同，並由CH1 主電源輸出調整鈕控制電壓大小,並聯追蹤模式：輸 出電壓與最大電流完全由CH1 控制，可提供最多一倍的電流輸出,輸出 控制開關OFF 時輸出端隔離，無電壓輸出也無法顯示設定的最大電流 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (123, 'multiple', '62. (123) 使用三用電表量測某電路各點結果分別如下圖A、B、C、D，下列之判讀 何者正確？', '當指針偏轉於圖中A 所示位置且檔數置於ACV 1000V 時，量測之交流電壓值約為460V,當指針偏轉於圖中B 所示位置且檔數 置於ACV 250V 時，量測之交流電壓值約為165V,當指針偏轉於圖中C 所示位置且檔數置於ACV 50V 時，量測之交流電壓值約為42V,當指針 偏轉於圖中D 所示位置且檔數置於ACV 10V 時，量測之交流電壓值約為 3.3V ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (124, 'multiple', '63. (12) 若將一大小為60 伏特之直流電壓源加至兩個電阻大小，分別為5 歐姆與 10 歐姆，且串聯之電阻電路，下列敘述何者正確？', '總電阻等於15 歐姆,總電流等於4 安培,5 歐姆上的壓降為40 伏特,10 歐姆上的壓降為 20 伏特 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (125, 'multiple', '64. (13) 有關示波器被動式探棒及主動式探棒的比較，下列敘述何者正確？', '主 動式探棒適合高速訊號,被動式探棒適合高速訊號,主動式探棒適合低 電壓邏輯訊號,被動式探棒負載效應較小 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (126, 'multiple', '65. (234) 有三個都是6 歐姆的電阻，下列敘述何者正確？', '兩個串聯後再與第三 個並聯時電阻為6 歐姆,兩個串聯後再與第三個並聯時電阻為4 歐姆,兩個並聯後再與第三個串聯時電阻為9 歐姆,全部電阻並聯時電阻為2 歐姆 ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (127, 'multiple', '66. (14) ICT（In Circuit Test）基本上可以執行檢測出下列哪些功能或零件缺陷？', '開路,冷/假焊,零件「偏移」,短路 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (128, 'multiple', '67. (124) 使用ICT（In Circuit Test）測試電路板的優點為', '測試速度快、時間短,產品修理成本大幅降低,提高電路板佈線的使用率,提高產品品質 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (129, 'multiple', '68. (34) 數位儲存示波器功能，下列何者正確？', '系統架構中，不須衰減器,觸 發控制可以選擇水平觸發位準,垂直解析度是指將輸入電壓轉換成數位 值的精準度,將訊號數位化後重建波形，具有記憶與儲存功能 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (130, 'multiple', '69. (34) 數位儲存示波器中，下列對於觸發的敘述何者正確？', '邊緣觸發是一種 以時間點做為條件的觸發，只要訊號跨過某時間點就觸發,脈波寬度是 一種以頻率區間來當作條件的觸發模式，只要波寬大於頻率區間就觸發,低準位觸發允許擷取和檢視越過一個邏輯臨界值、但沒有同時越過兩個 邏輯臨界值的脈衝,觸發設定可針對輸入訊號的特定條件作出回應 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (131, 'multiple', '70. (14) 數位儲存示波器中，在不同的X：Y 比率頻率下，相位偏移量測結果，下 列敘述何者正確？', 'X：Y=1：1,X：Y=1：2,X：Y=1：3,X：Y=1：4 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (175, 'multiple', '44. (123) 有關PVC 導線規格及導線作業，下列敘述何者正確？', '其規格中的安全 電流量係以周圍溫度35°C 為準,應使用PVC 絕緣膠帶纏繞連接部分並 掩護原導體之絕緣外皮15 公厘以上,如規格標示22 ㎜2，表示其為多股 絞線,絞線接於開關時，如在線頭加焊錫或使用壓接端子，可降低耐張 強度 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (176, 'multiple', '45. (14) 使用鉗子剪線時，應注意', '鉗口凹槽應朝外,鉗口凹槽應朝內,線頭應 朝上,線頭應朝下 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (177, 'multiple', '46. (134) 有關電子工作法的敘述，下列何者正確？', '斜口鉗在電子元件裝配後， 剪除多餘的導線,使用指針式三用電表測量電壓時，會撥在歐姆檔最高 檔位，以免電表燒毀,驗電起子可用來判別380V 以下的交流電壓,IC 拆除後，可用吸錫線（絲）來吸取多餘之焊錫 ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (178, 'multiple', '47. (12) 下列哪些化學物質常用於錫焊接時之助焊劑？', '松香,氯化銨,氯化鐵,氯化銅 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (179, 'multiple', '48. (13) 使用一般電路圖繪圖工具軟體時，下列敘述何者正確？', '輸入信號端子 在左方，輸出信號端子在右方,輸入信號端子在右方，輸出信號端子在 左方,電源正端在上方、負端在下方,電源正端在下方、負端在上方 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (180, 'multiple', '49. (34) 依據PC 板裝配原則，下列敘述何者正確？', '先裝較高的元件，次裝較矮 的元件,易受雜訊干擾之電路，其裝配位置應儘量靠近電源,裸銅線焊 接於電路板上時，彎曲角度以90°與135°為原則,在安裝較大瓦特值的電 阻器時，必須要與PC 板保持散熱距離 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (181, 'multiple', '50. (124) 依據本職類技能檢定焊接作業規則，下列敘述何者正確？', '焊接面須使 用裸銅線，且其間距不得小於2.5 ㎜,焊接後之接腳長度不得超過0.5 ㎜，但IC 座不需剪除,裸銅線轉折處應焊接，且兩焊點間之空點不得超 過10 個,焊接時焊錫量應適中，不得有氣泡及冷焊現象 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (182, 'multiple', '51. (123) 使用萬用板裝配電子元件並加以焊接時，下列敘述何者正確？', '小型元 件優先裝配,裸銅線應平貼板面,裸銅線轉折處必須焊接,1W 以上電 阻器需平貼板面 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (183, 'multiple', '52. (23) 世界知名組織對無鉛焊錫的定義，下列何者正確？', '美國JEDEC：＜ 0.5wt ％Pb,日本JEIDA：＜0.1wt ％Pb,歐盟EUELVD：＜0.1wt ％Pb,國際OPEC：＜0.05wt ％Pb ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (184, 'multiple', '53. (13) 在表面黏著技術SMT 生產製程中，在貼片階段可能產生的不良現象為', '側立,冷焊,反面,連錫 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (185, 'multiple', '54. (123) 表面黏著元件SMD 的修補工具為何？', '烙鐵,拆焊台,吸錫器,IC 拔取器 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (186, 'multiple', '55. (14) 一般SMT 製程中，使用的錫膏，其成分包含', '助焊劑,碳粉,矽粉,錫粉 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (187, 'multiple', '56. (124) 下列何者是2 層板的PCB 設計Power/GND 鋪銅處理重要的考慮因素？', '隔絕雜訊,電源供應穩定,打Via 換層的位置,GND 銅箔的均勻分 布 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (188, 'multiple', '57. (123) 在PCB 佈線設計中，為了做出優質的電子產品，需整合哪些人員的設計 概念？', 'EMI 工程師,安規工程師,機構工程師,軟體工程師 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (189, 'multiple', '58. (123) 鋼板的開孔型式為', '方形,本疊板形,圓形,三角形 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (280, 'multiple', '91. (123) 有關二極體特性之敘述，下列何者正確？', '稽納二極體摻雜濃度高於一 般二極體,稽納二極體工作於逆向偏壓，具有穩壓作用,稽納二極體 在順向偏壓時，具有整流作用,二極體內的過渡電容（Transition Capacitance），電容量隨逆向偏壓增加而增加 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (281, 'multiple', '92. (124) 兩個共射極放大器構成RC 耦合串級放大電路，下列敘述何者正確？', '第一級直流工作點的變化不會影響到第二級的直流工作點,高頻的電壓 增益受到極際電容的影響而降低,第一級直流工作點的變化會影響到第 二級的交流電壓增益,低頻的電壓增益受到耦合電容的影響而降低 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (282, 'multiple', '93. (123) 下圖之電路，下列敘述何者正確？', '該電路為RC 耦合電路，容易隔離 兩級間直流電壓的相互干擾,R1、R2 為偏壓電阻，提供電晶體偏壓,CE2 為旁路電容，可提高電壓增益,RE 1 及RE2 為正回授電阻，可穩定直 流偏壓，不受溫度變化影響 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (283, 'multiple', '94. (134) 下列哪些型振盪器之輸出電壓為正弦波？', 'RC 相移振盪器,電晶體組 成不穩態多諧振盪器,Wien bridge 振盪器,Colpitts 振盪器 ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (284, 'multiple', '95. (124) 電阻器在下列哪些情況會過熱而燒毀？', '0.5k-1W 電阻器流過50mA,3W 電阻器流過0.3A 與兩端電壓為13V,2k-1/2W 電阻器兩端電壓為 20V,1-3.5W 電阻器流過2A ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (285, 'multiple', '96. (23) 已知一顆高亮度LED 正常點亮的順向電壓為3.2V 與順向電流為10～ 15mA，則下列哪些為下圖中之R1 合理值？', '390,270,200,100 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (286, 'multiple', '97. (134) 下列哪些元件具有正電阻的特性？', '稽納二極體,隧道（透納）二極 體,變容二極體,場效應電晶體 ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (287, 'multiple', '98. (14) 理想的電壓運算放大器（OPA）的敘述，下列何者正確？', '輸入阻抗= 無限大；輸出阻抗=0,輸入阻抗=0；輸出阻抗=無限大,輸入阻抗=無 限大；輸出阻抗=無限大,頻帶寬度=無限大；輸出增益=無限大 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (288, 'multiple', '99. (123) 有關電子電路回授的敘述，下列何者正確？', '正回授常用來產生震盪,負回授會降低電路之電壓增益,回授是指將放大器的輸出訊號取出一 部分或全部，重新送回輸入電路,負回授可以穩定電路，但是容易使輸 出波形失真 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (289, 'multiple', '100. (24) 已知交流電壓v(t)=5sin(60t+30°)V，下列敘述何者正確？', '有效值為5V,最大值為5V,頻率為60Hz,相角為30° ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (290, 'multiple', '101. (234) 下圖所示，若Vcc=5V，LED 順向電壓為1.7V，順向電流界定在10mA ～20mA 之間，則R x 應可選用下列哪些電阻較合適？', '150Ω,220Ω,270Ω,300Ω ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (291, 'multiple', '102. (23) 下圖為一典型直流穩壓電源調整電路，Vbe=0.7V，其輸出電壓可調整之 範圍，下列敘述何者正確？', '最小2.7V,最小3.3.V,最大18.3V,PAGE 33 of 85 最大21V ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (292, 'multiple', '103. (12) BJT 電晶體各種組態中，下列哪幾項屬於CC 組態的特徵？', '電流增益 最高,輸入阻抗最高,電壓增益最高,輸出阻抗最高 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (293, 'multiple', '104. (12) 橋式全波整流電路圖如下，下列敘述何者正確？', 'D1、D4 順向偏壓 時，D2、D3 逆向偏壓,D2、D3 順向偏壓時，D1、D4 逆向偏壓,D1、D2 順向偏壓時，D3、D4 逆向偏壓,D3、D4 順向偏壓時，D1、 D2 逆向偏壓 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (294, 'multiple', '105. (124) 場效電晶體（FET）包含哪些應用？', '壓變電阻,電阻負載,負電阻,記憶裝置 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (295, 'multiple', '106. (14) 下圖之半波整流電路中，輸入電壓Vi(t)=200sin(377t)V，下列敘述何者 正確？', 'Vo(t)的頻率為60Hz,Vo(t)的有效值為63.6V,Vo(t)的平均 值為100V,二極體的PIV 值為200V ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (296, 'multiple', '107. (24) 理想運算放大器的特性，下列敘述何者正確？', '輸出阻抗為無限大,差動輸入時，共模拒斥比（CMRR）無限大,輸入阻抗為零，即輸入電 流Ii=0,頻帶寬度無限大 ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (297, 'multiple', '108. (23) 下圖之CE 放大器中，VCC=20V，β=120，VBE=0.7V，下列何者正確？', 'IB=28.38μA,IC=1.86mA,VC E=11.26V,V BC=10.56 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (298, 'multiple', '109. (123) 有關電晶體直流組態中，下列敘述何者正確？', '就輸入阻抗而言CB＜ CE＜CC,功率增益以CE 組態最大,放大器的後級使用CC 組態是為 了作阻抗匹配和放大電流用,就電壓放大倍數比較，50 比-50 來得大 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (299, 'multiple', '110. (13) 有關二極體的使用，下列敘述何者正確？', '1N4001 為PN 二極體編號,一般有白色環狀帶或有標記的一端為P,可使用三用電表歐姆檔測試 二極體好壞,所有二極體若要正常工作，皆需要加順向偏壓 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (300, 'multiple', '111. (14) 下列敘述何者正確？', '低雜質濃度的半導體，溫度升高，電阻降低,絕緣體的溫度升高，電阻增加,金屬導體的溫度升高，傳導性增加,高雜質濃度的半導體，溫度升高，電阻增加 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (301, 'multiple', '112. (12) 在矽半導體材料中，摻入五價元素後，下列敘述何者正確？', '屬於N 型 半導體,少數載子為電洞,屬於P 型半導體,少數載子為電子 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (302, 'multiple', '113. (12) 有關電晶體特性曲線敘述，下列何者正確？', '集極輸出特性曲線表示的 是VCE 與IC 之間的關係,基極輸入特性曲線表示的是VBE 與IB 之間 的關係,繪製集極輸出特性曲線時是以IC 為參考基準,VCE 對VBE 與IC 之間的關係影響很大 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (303, 'multiple', '114. (12) 有關電晶體直流參數之敘述，下列何者正確？', ',,,', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (304, 'multiple', '115. (13) 一部電源供應器，其輸出阻抗為2Ω，開路電壓為30V，滿載電流為 2.5A，VR 為電壓調整率（Voltage Regulation）、V NL 為開路電壓、V FL 為滿載電壓，下列何者正確？', '定義為VR=(V NL-V FL)/V FL*100％,定 義為VR=(V NL-V FL)/V NL*100％,VR=20％,VR=17.67％ ', '0,2', '');
