INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (306, 'multiple', '117. (234) 下圖之電路中，下列何者正確？', '總電組RT=4Ω,總電流IT=5A,流 經6Ω的電流I6Ω=0,流經2Ω的電流I2 Ω=2.5A ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (307, 'multiple', '118. (34) 有關磁力線之敘述，下列何者正確？', '磁鐵內部由N 到S,磁力線無 論進入或離開磁鐵均與其表面平行,磁力線是封閉曲線,磁力線彼此 不相交 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (308, 'multiple', '119. (34) 理想電壓源與電流源內阻，下列敘述何者正確？', '電壓源內阻愈大愈好,電流源內阻愈小愈好,電壓源內阻愈小愈好,電流源內阻愈大愈 好 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (309, 'multiple', '120. (234) 有關電子電路中，達靈頓（Darlington）放大器之特性，下列敘述何者正 確？', '電壓增益高,電流增益高,輸入阻抗高,輸出阻抗低 ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (310, 'multiple', '121. (124) 下列何者是振盪所必要的條件？', '必須是正回授,回授因數βA 必須為 ≧1,必須有電感器,必須有維持振盪的足夠能量 ', '0,1,3', '');
