INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (412, 'multiple', '101. (24) 一顆八位元左移暫存器，如八位元輸出初始值為00000000，左移輸入 Din 為來自於最左邊位元的反相輸出，當經過50 個以上CK 後，則', '八 位元輸出保持為11111111,每個位元輸出工作週期均為50％,每個位 元輸出頻率均為CK 頻率除以8,每個位元輸出頻率均為CK 頻率除以 16 ', '1,3', '');
