INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (427, 'multiple', '116. (23) 如下列真值表所示，下列輸出函數何者正確？', 'Y0=(EAB)′,Y1=E′B,Y2=E′(A′B+AB′),Y3=E′(A′B′+AB) ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (428, 'multiple', '117. (23) 下列哪些正反器的激勵表正確？', 'SR 正反器激勵表,D 型正反器激勵表,JK 正 反器激勵表,T 型正反器激勵表 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (429, 'multiple', '118. (23) 在Verilog 電路敘述中，識別字的命名規則為', '第一個字元必須是英文 字母或數字,識別字的長度沒有限制,第二個之後的字元可以是英文字 母、數字、底線（_）或錢字號（$）,識別字沒有區分英文大小寫 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (430, 'multiple', '119. (234) 如下列真值表所示，其輸入和輸出關係為', 'Y1=A⊙B⊙C,Y1=A⊕B⊕ C,Y0=AB+AC+BC,Y0=AC+BC+ABC′ ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (431, 'multiple', '120. (13) 十進位值69 可轉換為', 'BCD 碼01101001,格雷碼（Gray code） 01100011,超三碼（Excess-3 code）10011100,二進位碼00100101 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (432, 'multiple', '121. (13) 有關數字表示法之互換，下列何者正確？', '(526.5) 10=(20E.8)1 6,(765.1) 8=(1D5.2) 16,(7A.8) 1 6=(1111010.1) 2,(1010101.1) 2=(84.5) 1 0 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (433, 'multiple', '122. (24) 下圖之電路的輸入、輸出組合中，下列敘述何者正確？', '(A,B,F)=(0,0,1),(A,B,F)=(0,1,0),(A,B,F)=(1,0,1),(A,B,F)=(1,1,0) ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (434, 'multiple', '123. (34) 設計邏輯電路時，下列敘述何者正確？', '使用NAND-NAND 製作邏輯 電路時，於卡諾圖中是取1 的方格產生和項之積,使用NOR-NOR 製作 邏輯電路時，於卡諾圖中是取0 的方格產生積項之和,使用AND-OR 製 作邏輯電路時，於卡諾圖中是取1 的方格產生積項之和,使用OR-AND 製作邏輯電路時，於卡諾圖中是取0 的方格產生和項之積 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (435, 'multiple', '124. (123) 如果要設計Mod 10 之計數電路，使用正反器的數量x 及最高位元輸出之 工作週期d，下列敘述何者正確？', '環形計數器：x=10，d=10％,強生 計數器：x=5，d=50％,漣波上數計數器（0,1,2,…,9）：x=4，d=20％,漣波下數計數器（0,15,…,7）：x=4，d=20％ ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (436, 'multiple', '125. (12) 中央處理器（CPU）是由下列哪兩大部門所組成？', 'ALU,CU,ROM,RAM ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (437, 'multiple', '126. (12) 由3 個JK 正反器所組成的強森計數器，可以有下列哪些模數（Mod- N）？', '5,6,7,8 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (438, 'multiple', '127. (12) 下圖所示，其功能之敘述下列何者正確？', '並列加法器,並列減法器,串列加法器,串並列減法器 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (439, 'multiple', '128. (12) 下圖所示，其功能之敘述下列何者正確？', '非同步計數器,下數計數器,上數計數器,同步計數器 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (440, 'multiple', '129. (13) 化簡如下列之卡諾圖，其邏輯函數應為何？', 'A′C+AB+AC′,A′C+CD+AC′,(A+C)(A′+B+C′),(A′+C′)(A+B′+C) ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (441, 'multiple', '130. (13) 有關在Verilog HDL 中有兩種主要資料型態，下列何者正確？', '線路 （Nets）：代表連線，不能儲存內容，代表閘或模組之間的連線，不可 以被指定（assign）,線路（Wire）：代表連線，不能儲存內容，代表 閘或模組之間的連線，可以被指定（assign）,暫存（Reg）：代表存儲 空間，就像暫存器一樣，儲存某值，直到下次被指定（assign）為止,記憶體（Rom）：代表存儲空間，就像暫存器一樣，儲存某值，直到下 次被指定（assign）為止 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (442, 'multiple', '131. (12) 一般而言，相同等級的FPGA 和CPLD 互相比較，下列敘述何者正確？', 'FPGA 的正反器比較多,FPGA 比較適用於計數器的設計,FPGA 較 適用於解碼電路,CPLD 的邏輯方塊（Block）數量比較少 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (443, 'multiple', '132. (14) 2 對1 多工器A（延遲時間為T），取3 組2 對1 多工器A 不外加其他 元件，組合成多工器B，下列何者正確？', 'B 為4 對1 多工器,B 為6 對1 多工器,B 的傳播延遲約等於T,B 的傳播延遲約等於2T ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (444, 'multiple', '133. (34) 組合邏輯電路的邏輯突波（hazard），發生在當輸入變數改變時，輸出 狀態產生暫時性錯誤，下列敘述何者正確？', '輸出值應維持0 卻產生 010 的狀態變化稱為動態突波,輸出信號值由0 變為1 時卻產生0101 的 狀態變化稱為靜態突波,對同一輸入信號有不同傳遞路徑，且彼此間的 傳播延遲有差異所造成的,加入適當質隱項可消除突波 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (445, 'multiple', '134. (23) 有關Verilog HDL 四個抽象的描述層次，下列敘述何者正確？', 'NOT 閘 屬於開關層次,RTL 為行為層次與資料流層次的混合描述,邏輯閘層 次屬於結構描述而非行為描述,邏輯閘為最低層次模組 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (446, 'multiple', '135. (14) 有關移位暫存器的應用，下列敘述何者正確？', '左移常用在乘法運算,左移常用在除法運算,算術左移時MSB 會做符號擴展,移位運算也用 在浮點數運算 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (447, 'multiple', '136. (12) 下圖之電路的功能為何？', '並列加法器,並列減法器,串列式加法器,串列式除法器 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (448, 'multiple', '137. (134) 有關可程式規劃邏輯元件（PLD），若依AND-OR 輸入端保險絲陣列是 否可規劃或固定式來加以分類，下列何者屬於AND 端可規劃的類別？', 'PAL,PROM,GAL,FPGA ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (449, 'multiple', '138. (34) 下圖所示，下列敘述何者正確？', 'C1 充放電壓振幅為0V～3V,OUT 電壓輸出之頻率為500Hz,第5 腳CON 電壓為8V,OUT 電壓輸出之 工作週期約50％ ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (450, 'multiple', '139. (23) 下列何者正確？', '(X+Y)(X+Y′)=X+YX,X+YZ=(X+Y)(X+Z),XY′+Y=X+Y,(X+Y′)Y=X′Y ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (451, 'multiple', '140. (12) 下列何者等同XNOR 電路？', ',,,', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (537, 'multiple', '86. (123) 有關CPU 的敘述，下列何者正確？', 'ALU 用來做算術及邏輯運算,暫 存器用來幫助CPU 做運算或暫存資料之用,指令暫存器用來暫存讀入 CPU 內的指令碼,某N 位元的CPU，此N 位元是指位址匯流排之數 目 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (538, 'multiple', '87. (23) 有關中央處理單元（CPU）的敘述，下列何者正確？', 'CPU 目前執行的 指令儲存於程式計數器（Program counter）中,CPU 內部的位址匯流排 有34 條，表示主記憶體的最大可定址空間有16GB,若CPU 的速度為 200MIPS，代表CPU 平均執行一個指令所需的時間為5ns,單核心微處 理器可用於多工環境的作業系統下，指揮各單元進行平行處理 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (539, 'multiple', '88. (234) 下列哪些項目與微處理機的處理速度有關？', 'Address Bus 的位元數,管線式的指令作業,時脈的頻率,Data Bus 的位元數 ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (540, 'multiple', '89. (234) 十六進制資料依序運算B9H AND 3FH XOR AEH，下列哪些不同進制資 料值為其等效結果？', '10100111 2,227 8,151 1 0,97H ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (541, 'multiple', '90. (234) 有關簡單型可程式規劃邏輯元件（SPLD）的敘述，下列何者正確？', '最常被使用到的SPLD 型態是用T 型正反器和PAL 組合在一起,Macrocell 包含一個積之和（SOP）的組合邏輯函數和一個可自由選擇的 正反器,SPLD 在積體電路元件內除了有AND-OR 陣列外，還包括了正 反器,SPLD 的每個部分被稱做Macrocell，一個Macrocell 就是一個電 路 ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (542, 'multiple', '91. (124) 一個典型的SPLDIC，它的包裝裡包含8-10 個Macrocell，Macrocell 的 規劃是可以選擇的，其規劃特色包含下列何者？', '暫存器的清除與設定 的選擇,選擇時脈邊緣觸發的極性,所有的正反器都有獨立的時脈輸 入,使用或不使用正反器的能力 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (543, 'multiple', '92. (12) 電腦系統中，下列何者屬於非加權碼？', 'BIG-5,ASCII,BCD,二進 制碼 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (544, 'multiple', '93. (134) 有關保護智慧財產權的各項法律中，下列何者其取得保護的方法須經過 申請登記或審查核准方能產生效力？', '積體電路電路布局保護法,著 作權法,專利法,商標法 ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (545, 'multiple', '94. (124) 有關微電腦系統的起動，下列敘述何者正確？', '啟動程式（Booting） 可透過硬體按鈕或軟體指令啟動一組程序，用來初始化電腦系統或裝置,Bootloader 是指一組程式當電腦系統完成自我診斷後，協助載入作業 系統或一組程式,Bootloader 會先被存在SRAM 中，再被載入主記憶體 執行,可透過JTAG 界面直接燒錄Bootloader ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (546, 'multiple', '95. (123) 有關微處理器之外部中斷信號被偵測到時，下列敘述何者正確？', '程式 計數暫存器會被堆疊保存,跳至中斷向量所指示的位址,執行中斷向 量為起始位址的中斷副程式,不再接受任何中斷 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (547, 'multiple', '96. (23) 當89S51/52CPU 的RESET 腳接高準位超過2 個機械週期時，會產生重 置動作，下列敘述何者正確？', '內部RAM 都清除為0,埠1（Port 1） 為11111111B,暫存器SP 的內容為00000111B,暫存器DPTR 的內容 為FFF0H ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (548, 'multiple', '97. (13) 有關微電腦設備，其CPU 之資料匯流排（Data Bus）與位址匯流排 （Address Bus）各有32 條，下列敘述何者正確？', '這是一部32 位元 的電腦,這部電腦的CPU 最大定址能力為32GB,這部電腦一次可以 處理4 位元組的資料,電腦最大主記憶體容量為32GB ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (549, 'multiple', '98. (124) 有關微處理器，下列敘述何者正確？', '指令週期包括擷取、解碼、執行 及儲存等四個步驟,電腦工作頻率（Clock Frequency）的倒數即為時脈 週期（Clock Cycle）,單核心微處理器不能用於多工環境的作業系統,具有超過2 個以上CPU 的電腦，可稱之為「多核心CPU」電腦 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (550, 'multiple', '99. (123) 下列哪幾項作業系統較適用於嵌入式系統？', 'Android,iOS,uCLinux,Unix ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (551, 'multiple', '100. (12) 下列哪幾項是屬於開源（Open Source）嵌入式軟硬體協同開發系統？', 'Arduino,Raspberry Pi,AndeShape,ZedBoard ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (552, 'multiple', '101. (12) 有關直接記憶體存取（DMA），下列敘述何者正確？', '可以與CPU 同 步作業,協助記憶體資料存取的機制,是唯讀記憶體（ROM）的一種,屬於快取記憶體（cache memory） ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (553, 'multiple', '102. (12) 有關嵌入式系統，下列敘述何者正確？', '一定會有中央處理器,一定 會有記憶體,一定要有螢幕顯示器,一定要有JTAG 介面 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (554, 'multiple', '103. (12) 有關哈佛架構，下列敘述何者正確？', '程式記憶體與資料記憶體可各自 獨立存取,ARM9 採用此架構,與范紐曼架構相同但效能較高,指令 和資料的寬度必須一致 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (555, 'multiple', '104. (12) 有關8 位元微控制器的定義，下列敘述何者正確？', '資料暫存器為8 位 元,資料匯流排為8 位元,位址匯流排為8 位元,計時器為8 位元 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (556, 'multiple', '105. (12) 用微控制器控制LED 亮度，下列敘述何者正確？', '加入DAC 電路,採用PWM 方法,加入記憶體,採用DMA 方法 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (557, 'multiple', '106. (12) 有關ISP（In-System Programming），下列敘述何者正確？', '常用 JTAG 協定界面,可以即時修改程式,是一種獨立式燒錄器,常使用 IEEE-488 界面 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (558, 'multiple', '107. (124) 下列何種介面是以串列的方式傳遞資料？', 'PCI-Express,SATA,AGP,IEEE-1394 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (559, 'multiple', '108. (124) 有關各種周邊設備的介紹，下列何者正確？', '印表機的解析度通常使用 DPI 來表示,雷射印表機列印時宜在通風處,數據機的傳輸速度若以 bps 表示，代表一秒鐘所傳輸的byte 數量,滑鼠是Windows 作業系統 中，常用的輸入設備 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (560, 'multiple', '109. (13) 下列哪些為微電腦介面串列資料傳輸為2M 之真正含意？', '2048Kbits/s,2Mbytes/s,2Mbits/s,2Mwords/s ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (561, 'multiple', '110. (124) 下列哪些傳輸媒體易受電磁干擾？', '微波,同軸電纜,光纖,雙絞 線 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (562, 'multiple', '111. (123) 中斷查詢方式：A.硬體查詢、B.軟體查詢、C.向量式，下列何者為其正 確的回應優先順序？', 'ABC,AC,BC,CA ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (563, 'multiple', '112. (123) 有關微電腦系統，下列敘述何者正確？', 'USB 的傳輸速率比IEEE-488 快,暫存器的資料存取的時間比DDRRAM 快,RS-232C 的傳輸速率比 USB 慢,當CPU 執行中斷時，不能再接受其他中斷 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (564, 'multiple', '113. (123) 下列何種微處理器架構採用平行處理的方式運算？', '單指令多資料流 SIMD（Single Instruction Multiple Data）,多指令多資料流MIMD （Multiple Instruction Multiple Data）,多管線（pipelining）,多指 令單資料流MIPS（Multiple Instruction Per Stream） ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (565, 'multiple', '114. (123) 下列資料傳輸方式何者採用無線通訊技術？', 'Bluetooth,RFID,NFC,Ethernet ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (566, 'multiple', '115. (12) 有關藍芽裝置，下列敘述何者正確？', '適合射頻頻率2.45GHz,使用跳 頻技術對抗干擾,屬於一種高功率的長距離無線傳輸技術,僅可一對 一連線進行資料傳輸 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (567, 'multiple', '116. (14) 有關USB 界面特性，下列敘述何者正確？', '由一個USB 主機和數個 USB 集線器，透過分層星型拓撲結構，連接USB 裝置,USB 集線器需 要終端子,USB 的Type-A 與Type-B 兩種連接器均可用於主機和周邊 裝置,USB 傳輸線中，有2 條訊號線為標記D+和D-的雙絞線 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (568, 'multiple', '117. (134) 對於6 線2 相200 步之步進馬達，下列敘述何者正確？', '採1 相激磁方 式，需要200 個驅動信號才能轉1 圈,步進角度為0.9°,採1-2 相激磁 方式，需要400 個驅動信號才能轉1 圈,採1-2 相激磁方式，每個驅動 信號產生0.9°位移 ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (569, 'multiple', '118. (134) USB 的規格標準中，下列敘述何者正確？', 'USB2.0 傳送的速率為 480Mbps,USB3.0 傳送的速率為1Gbps,USB3.1 傳送的速率為 10Gbps,USB1.1 傳送的速率為12Mbps ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (570, 'multiple', '119. (234) 有關解析度的敘述，下列何者正確？', '使用200dpi 解析度的掃描器掃 描4×6 吋的黑白照片，在不壓縮的狀況下，大約要花費120MB 的記憶空 間來儲存,掃描一張3×5 吋的照片後，儲存時顯示為900×1500 畫素， 則此掃描器的解析度最有可能設定為300dpi,Full HD 的顯示器其解析 度可高達1920×1080,解析度1024×768 全彩的顯示器畫面，需大約耗 費2.25MB 的記憶體 ', '1,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (571, 'multiple', '120. (124) 下列介面兼具串列傳輸與熱插拔特性的有哪幾種？', 'USB 2.0,IEEE- 1394b,SCSI,SATA ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (572, 'multiple', '121. (34) 面臨缺水的環境中，須懂得如何珍惜水資源，可以使用無線環境感測 器，感知土壤內的溫、濕度，並定期將資訊透過聯網閘道器回報給雲端 進行運算，以便讓農地灌溉系統進行即時控管，其所使用的無線環境感 測器之通訊技術，以下列哪幾項較合適？', 'Bluetooth,NFC,Wi-Fi,ZigBee ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (573, 'multiple', '122. (123) 下列哪幾項通訊技術是屬於個人區域網路（Personal Area Network）技 術？', 'NFC,Bluetooth,IrDA,Wi-Fi ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (574, 'multiple', '123. (12) 下列哪些裝置是屬於周邊設備的輸入裝置？', '鍵盤與數位板,觸控螢 幕與掃描器,觸控筆與雷射筆,麥克風與耳機 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (575, 'multiple', '124. (12) 有關RS-232C 通訊電路的敘述，下列何者正確？', '傳送距離可達50 英 呎,採用串列傳輸,傳送電路採用+5V 電源,傳送訊號無方向性 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (576, 'multiple', '125. (12) 有關RS-232C 與GPIB 通訊電路的敘述，下列何者正確？', 'RS-232C 以 串列方式輸出,GPIB 以並列方式輸出,RS-232C 的傳輸距離比GPIB 短,RS-232C 的資料線比較多 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (577, 'multiple', '126. (123) 下列哪些因素是造成RS-232 與電腦周邊連接，無法連線的原因？', '參 數（parameter）的設定不一致,訊號準位不同,資料傳送速度不一致,使用不同廠牌的RS-232 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (578, 'multiple', '127. (124) 有關數位訊號處理器（DSP）的敘述，下列何者正確？', '可進行平行處 理,強調高速計算,著重在大量資料的存取,可用於單指令多數據流 （SIMD） ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (579, 'multiple', '128. (23) 有關位址匯流排（Address Bus）的敘述，下列何者正確？', '可以決定最 高的處理速度,可以決定最大的定址能力,不能決定單位時間的指令 執行數量,可以決定最大功率損耗 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (580, 'multiple', '129. (24) 下列哪些為固態硬碟（SSD）的特性？', '內部具有超高速微馬達,一種 半導體的儲存裝置,與DRAM 同特性,等同於超大容量的隨身碟 ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (646, 'multiple', '66. (134) C 語言程式中，x=0x26，y=0xe2，下列敘述何者正確？', '執行z=x&y 後，z=0x22,執行z=x|y 後，z=0x66,執行z=x＜＜3 後，z=0x30,執 行z=y＞＞2 後，z=0x38 ', '0,2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (647, 'multiple', '67. (12) 下列何者是C 語言提供的關鍵字（keyword）？', 'break,while,character,integer ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (648, 'multiple', '68. (14) C 語言程式中，if(y＜0) x=-y ; else x=y;使用『?:』替換，可寫成', 'x=y ＜0?-y:y,x=y＜0?y:-y,y=y＜0?x:-x,x=y＞0?y:-y ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (649, 'multiple', '69. (13) 程式執行中，變數的存取範圍（scope）和生命週期（life time），下列何 者正確？', '區域（local）變數：僅能在該變數的宣告函式內存取,靜態 （static）變數：其生命週期跟程式一樣長，可以在宣告的函式外存取,全域（global）變數：整個程式中都可以存取,變數是存放位置在stack 或heap 記憶體中 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (650, 'multiple', '70. (12) C 語言程式中，已知a=10，b=5，下列何者會造成無窮迴圈？', 'while (a ＞b) { a=a-b; b=b-a; printf("*"); },for (a=0; a＜b; a--) printf("*");,for (a=0; a＜b; ++a) { printf("*"); },while (a==b) { for (a=0;;) printf("*"); } ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (651, 'multiple', '71. (14) 下列C 語言程式，何者正確？', '執行至第10 列後，其輸出為： a=100,b=10,執行至第10 列，其輸出為：a=50,b=10,執行至第12 列， PAGE 77 of 85 其輸出為：a=350,b=360,執行至第12 列，其輸出為：a=100,b=360 ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (652, 'multiple', '72. (24) 若變數a,b 皆為整數，且a 和b 的值皆為0，則下列運算結果何者為 true？', 'a=b,a==b,a!=b,a＜=b ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (653, 'multiple', '73. (24) char、short int 分別佔用記憶體為1 個及2 個位元組（byte），變數 a,b,c,d 分別宣告為char a; unsigned char b; short int c; unsigned short int d;下列何者正確？', '執行a=28+100;結果a=128,執行b=28+100;結果 b=128,執行c=30000+2768;結果c=32768,執行d=30000+2768;結果 d=32768 ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (654, 'multiple', '74. (12) 已知ASCII Code a=97, A=65，若下列程式執行結果為King 或KING，程 式中之n[4]陣列初值要如何設定？', '{30, 5, -7},{-2, 5, -7},{32, 5, - 7},{22, 5, -7} ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (655, 'multiple', '75. (12) 有關標準C 語言中，union 執行下列程式後，請選出正確結果', 'a[0] = 0x64,sizeof(A1) = 8,A1.a = 10,sizeof(A1) = 12 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (656, 'multiple', '76. (12) 有關標準C 語言中，結構（struct）定義的記憶體安排，下列程式中， sizeof(A)與sizeof(B)分別為', 'sizeof(A)=24,sizeof(B)=16,sizeof(A)=14,sizeof(B)=14 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (657, 'multiple', '77. (12) C 語言程式中，執行時的靜態記憶體（Static Memory）區段有', 'code(text),data/bss,stack,heap ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (658, 'multiple', '78. (12) 相較標準C 編譯器，有關SDCC（Small Device C Compiler）編譯器的說 明，下列何者正確？', '結構（struct）不可以作為函數傳入參數,不支援 可變長度陣列（variable-length arrays）,支援雙精確浮點數,結構 （struct）可以作為函數回傳值 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (659, 'multiple', '79. (12) 相較於標準C 語言，有關Embedded C 新增定義的功能，下列何者正確？', '定點數學運算（fixed-point arithmetic）,地址空間命名（named address spaces）,物件導向（object-oriented）,巢狀結構體（nested- structure） ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (660, 'multiple', '80. (13) C 語言程式中，a=13，b=6，num=0，下列敘述何者正確？', '執行 num=(++a)+(++b)後，num=21、a=14、b=7,執行num=(a++)+(b++)後， num=21、a=14、b=7,執行a+=a+(b++)後，num=0、a=32、b=7,執行 a*=b--後，num=0、a=65、b=5 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (661, 'multiple', '81. (13) C 語言程式中的for、while 及do…while 三種迴圈，下列敘述何者正確？', 'for 迴圈是前端測試判斷條件,while 迴圈是後端測試判斷條件,do… while 迴圈至少執行迴圈主體1 次,do…while 迴圈是在測試判斷條件不 成立時，執行迴圈主體 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (692, 'multiple', '31. (24) 有關國際標準組織（ISO）所訂定之開放式系統連結（OSI）的參考模式 中，下列通信協定敘述何者正確？', '第一層為網路層,第二層為資料鏈 結層,第三層為實體層,第四層為傳輸層 ', '1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (693, 'multiple', '32. (23) 下列何者是無線網路較有線網路的優勢之處？', '具有複雜的線路,處理 行動式裝置的能力較佳,具有動態拓撲,可靠度較佳 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (694, 'multiple', '33. (23) 下列敘述何者正確？', 'TCP 負責將資料正確地送達發送端,IP 負責設定 IP 位址及選擇傳輸路徑,開放式系統連結（OSI）中的傳輸層對應至 TCP 與UDP,開放式系統連結（OSI）中，電子郵件（E-mail）的通信協 定是屬於網路層 ', '1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (695, 'multiple', '34. (34) 有關乙太網路（Ethernet）之敘述，下列何者正確？', '使用GR-58 同軸 電纜，以10Mbps 在500 公尺內傳輸信號，又稱為細線乙太網路,使用 RG-11 同軸電纜，以10Mbps 在200 公尺內傳輸信號，又稱為粗線乙太網 路,快速乙太網路中的規範是用Category 5 的雙絞線以100Mbps 在100 公尺內傳輸信號,快速乙太網路中的規範是用Category 6 的雙絞線以 1Gbps 在100 公尺內傳輸信號 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (696, 'multiple', '35. (12) 下列敘述何者正確？', '國際標準組織（ISO）將網路傳輸的規則訂定成七 層架構,開放式系統連結（OSI）中的應用層主要功能為各種網路應用程 式，如瀏覽器、電子郵件軟體、即時通,載波偵聽多重存取/碰撞偵測 （CSMA/CD）在碰撞發生後，偵測到碰撞的第一個設備有重傳的優先權,由傳輸層來決定傳輸路徑的選擇 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (697, 'multiple', '36. (13) 有關網路拓撲之敘述何者正確？', '環形架構屬於點對點拓撲,點對點拓 撲中，若只是一部電腦當機並不會影響整個網路的運作,匯流排架構是 屬於廣播拓撲,電腦教室的網路連接使用集線器的是屬環形架構 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (698, 'multiple', '37. (13) 有關雲端服務的敘述，下列何者正確？', '將資料傳送到網路伺服器服務 的模式可視為一種雲端運算,通常都是由廠商透過網路伺服器，僅能提 供儲存的服務資源,雲端伺服器可以提供某些特定的服務，例如網路硬 碟、線上轉檔與網路地圖等,目前仍然無法透過雲端服務線上直接編修 文件，必須在本地端的電腦上安裝辦公室軟體（Office Software）才能夠 編輯 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (699, 'multiple', '38. (14) 有關網路的拓撲（Topology）結構敘述，下列何者正確？', '匯流排 （Bus）結構適合廣播（Broadcast）的方式傳遞資料,樹狀（Tree）的結 構，可以形成封閉性迴路,網狀（Mesh）結構網路上的節點依環形順序 傳遞資料,星狀（Star）的結構，經常需要一個集線器（HUB） ', '0,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (700, 'multiple', '39. (13) 有關SSL（Secure Socket Layer）的敘述，下列何者正確？', '登入網頁 時，其中http 會變成https，代表使用了SSL,在網頁上輸入帳號密碼 時，使用SSL，密碼使用就萬無一失,用於網際網路的連線安全,是一 種網頁加密保護的機制 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (701, 'multiple', '40. (12) 有關Socket programming 下列何者正確？', 'server socket（node）會針對 一組IP 的特定port 進行監聽,client socket（node）會聯繫到一組 server socket（node），並建立通訊連接,client socket（node）會針對 一組IP 的特定port 進行監聽,server socket（node）會聯繫到一組 client socket（node），並建立通訊連接 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (702, 'multiple', '41. (12) 有關串列傳輸程式，下列何者正確？', '設定傳送與接收端相同的鮑率 （baud rate）,設定相同的資料格式，如byte 長度與同位位元數,設定 相同的系統頻率,使用相同的程式語言 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (703, 'multiple', '42. (123) 下列敘述何者正確？', '第五代（5G）行動通訊技術，主要為提升速度、 減少延遲而設計的,5G 技術的速度最快可達20Gbps,Wi-Fi 6 技術也稱 為IEEE 802.11ax,5G 採用WiMAX 技術 ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (731, 'multiple', '28. (13) 有關微電腦的I/O 位址控制敘述，下列何者正確？', '直接式I/O 位址不屬 於記憶體位址的一部分,記憶體映像式I/O 並不需佔用記憶體位址,具 有I/O 專用指令則為獨立式I/O 定址,記憶體映像式I/O 位址不需使用記 憶體存取指令 ', '0,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (732, 'multiple', '29. (34) 有關RS-232C 非同步傳輸的資料格式，下列敘述何者正確？', '啟始位元 （start bit）高電位為Space 狀態,啟始位元可有兩個位元,結束位元 （stop bit）高電位為Mark 狀態,結束位元可有兩個位元 ', '2,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (733, 'multiple', '30. (124) 下列哪些方式具有無線介面感測或傳輸功能？', '40kHz 超音波收發電路,光二極體收發電路,Pt 溫度組件,Bluetooth 裝置 ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (734, 'multiple', '31. (124) 有關CPU 的內部架構，包含下列哪些項目？', '控制單元（control unit）,算術運算與邏輯單元（ALU）,主記憶體（main memory）,暫存器 （register） ', '0,1,3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (735, 'multiple', '32. (12) 有關資料傳輸，下列敘述何者正確？', '非同步傳輸接收器（UART）彼此 之間的傳輸方式是屬於一種串列輸出串列輸入,在串列資料傳送時，依 PAGE 85 of 85 序由LSB 位元至MSB 位元,位址匯流排是屬於IEEE-488 的匯流排,控 制匯流排不是屬於IEEE-488 的匯流排 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (736, 'multiple', '33. (12) UART 為通用非同步傳收器的英文縮寫，為非同步串列通信埠的總稱，包 括', 'RS-232,RS-485,GPIB,IEEE-1284 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (737, 'multiple', '34. (12) 有關I 2C（Inter-Integrated Circuit），下列敘述何者正確？', '一種串列通 訊的匯流排,只使用兩條雙向開放洩極（open drain）傳輸線，分別為串 列資料（SDA）線及串列時脈（SCL）線,只使用兩條傳輸線，分別為傳 送資料（TD）線及接收資料（RD）線,用於高速裝置間的資料傳輸 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (738, 'multiple', '35. (12) 有關近場通訊（NFC）界面技術，下列敘述何者正確？', '可採用主動/被 動兩種讀取模式,短距離高頻無線通訊,傳輸距離可達1 公尺,短距離 低頻無線通訊 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (739, 'multiple', '36. (123) 於物聯網系統中，感測器為連接不同的硬體模組，模組間必須要透過傳輸 介面才得以成功交換資料，較適合的傳輸介面有下列哪幾項？', 'UART （Universal Asynchronous Receiver Transmitter）,SPI（Serial Peripheral Interface）,I2C（Inter-Integrated Circuit）,JTAG（Joint Test Action Group） ', '0,1,2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (740, 'multiple', '37. (12) 有關I 2C 界面，下列敘述何者正確？', '一種串列介面,使用集極開路 （open drain）,一種並列介面,工作電壓為5V ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (741, 'multiple', '38. (12) 有關I 2S 界面，下列敘述何者正確？', '一種串列界面,傳輸線中的字元 選擇時脈與聲音取樣頻率相同,一種並列介面,僅可傳輸單聲道數位音 訊資料 ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (742, 'multiple', '39. (12) C 語言程式的標準記憶體表現形式包括哪些動態記憶區域？', 'Heap,Stack,Code segment,Data segment ', '0,1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (743, 'multiple', '40. (12) 有關執行緒（thread）的敘述，下列何者正確？', '執行緒之間可共享程式 區段,執行緒之間可共享資料區段,執行緒之間共用堆疊區段,執行緒 之間共用程式計數器 ', '0,1', '');
